import React, { useState } from "react";

const moods = [
  { label: "Happy", emoji: "😊", color: "bg-yellow-400", text: "text-yellow-900" },
  { label: "Anxious", emoji: "😰", color: "bg-blue-400", text: "text-blue-900" },
  { label: "Tired", emoji: "😴", color: "bg-purple-400", text: "text-purple-900" },
  { label: "Focused", emoji: "🎯", color: "bg-green-400", text: "text-green-900" },
  { label: "Sad", emoji: "😢", color: "bg-gray-400", text: "text-gray-900" },
  { label: "Excited", emoji: "🚀", color: "bg-orange-400", text: "text-orange-900" },
];

export default function App() {
  const [selectedMood, setSelectedMood] = useState(null);

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-6">
      <h1 className="text-4xl font-bold text-gray-800 mb-2">MoodCast</h1>
      <p className="text-gray-500 mb-10">How are you feeling today?</p>

      <div className="grid grid-cols-3 gap-4 mb-10">
        {moods.map((mood) => (
          <button
            key={mood.label}
            onClick={() => setSelectedMood(mood)}
            className={`${mood.color} ${mood.text} rounded-2xl p-6 flex flex-col items-center shadow-md hover:scale-105 transition-transform duration-200 ${
              selectedMood?.label === mood.label ? "ring-4 ring-offset-2 ring-gray-800" : ""
            }`}
          >
            <span className="text-4xl mb-2">{mood.emoji}</span>
            <span className="font-semibold text-lg">{mood.label}</span>
          </button>
        ))}
      </div>

      {selectedMood && (
        <div className="bg-white rounded-2xl shadow-lg p-6 w-full max-w-md text-center">
          <p className="text-gray-600 text-lg">You selected</p>
          <p className={`text-3xl font-bold mt-1 ${selectedMood.text.replace("900", "600")}`}>
            {selectedMood.emoji} {selectedMood.label}
          </p>
          <button className="mt-6 bg-gray-800 text-white px-8 py-3 rounded-xl font-semibold hover:bg-gray-700 transition-colors">
            Generate My Day Plan ✨
          </button>
        </div>
      )}
    </div>
  );
}
